
import React from 'react'
import { FaBars } from "react-icons/fa";
import { LuLayoutDashboard } from "react-icons/lu";
import { MdCategory } from "react-icons/md";    
import { FaProductHunt } from "react-icons/fa";
import { IoMdColorPalette } from "react-icons/io";
import { IoMdSettings } from "react-icons/io";
import Link from 'next/link';
import { usePathname } from 'next/navigation';

export default function Sidebar() {
    const pathname = usePathname()
    console.log(pathname)
    const pages = [
        {
            name : "Dasboard",
            path : "/admin",
            icon :  <LuLayoutDashboard />
        },
        {
            name : "Category",
            path : "/admin/category",
            icon :  <MdCategory />
        },
        {
            name : "Products",
            path : "/admin/products",
            icon :  <FaProductHunt />
        },

        {
            name : "Colour",
            path : "/admin/colour",
            icon :  <IoMdColorPalette />
        },
        {
            name : "Setting",
            path : "/admin/setting",
            icon : <IoMdSettings />
        },
    ]
  return (
    <div className='w-74 h-lvh   bg-white shadow-2xl  text-black'>
        {/* title */}
      <div className='flex justify-between items-center px-4 py-4 border-b border-gray-500 ' >
            <h1 className='font-bold text-2xl text-orange-400'>Ishop<b className='font-bold text-black'>Admin</b></h1>
            <div>
            <FaBars className='text-xl cursor-pointer' />
            </div>
      </div>
      <div className='px-4 mt-10'>
        {
            pages.map((items,index)=>{
                return(
                    <Link key={index} href={items.path}>
                    <div className='flex  bg-orange-400 p-3 rounded-md items-center gap-6 mb-3 text-2xl'>
                    {items.icon}
                    <p >{items.name}</p>
                    </div>
                    </Link>
                )
                    
                
            })
        }
       
        
        
      </div>
    </div>
  )
}
